import { Entity, PrimaryGeneratedColumn, Column, CreateDateColumn, UpdateDateColumn, OneToMany, ManyToOne } from 'typeorm';
import { OrderItem } from './OrderItem';
import { MpesaTransaction } from './MpesaTransaction';
import { Payment } from './Payment';
import { Quote } from './Quote';
import { ColumnNumericTransformer } from '../utils/transformer';

export enum OrderStatus {
  PENDING = 'PENDING',
  PARTIALLY_PAID = 'PARTIALLY_PAID',
  PAID = 'PAID',
  FAILED = 'FAILED',
  SHIPPED = 'SHIPPED',
  DELIVERED = 'DELIVERED',
  CANCELLED = 'CANCELLED'
}

@Entity('orders')
export class Order {
  @PrimaryGeneratedColumn('uuid')
  id!: string;

  @Column({ unique: true })
  orderNumber!: string;

  @Column()
  customerName!: string;

  @Column({ nullable: true })
  customerEmail?: string;

  @Column()
  customerPhone!: string;

  @Column({ nullable: true })
  shippingAddress?: string;

  @Column('decimal', { precision: 10, scale: 2, transformer: new ColumnNumericTransformer() })
  totalAmount!: number;

  @Column('decimal', { precision: 10, scale: 2, default: 0, transformer: new ColumnNumericTransformer() })
  amountPaid!: number;

  @Column('decimal', { precision: 10, scale: 2, default: 0, transformer: new ColumnNumericTransformer() })
  balance!: number;

  @Column({
    type: 'enum',
    enum: OrderStatus,
    default: OrderStatus.PENDING
  })
  status!: OrderStatus;

  @OneToMany(() => OrderItem, (item) => item.order, { cascade: true })
  items!: OrderItem[];

  @OneToMany(() => MpesaTransaction, (tx) => tx.order)
  mpesaTransactions!: MpesaTransaction[];

  @OneToMany(() => Payment, (payment) => payment.order, { cascade: true })
  payments!: Payment[];

  @ManyToOne(() => Quote, { nullable: true })
  sourceQuote?: Quote;

  @CreateDateColumn()
  createdAt!: Date;

  @UpdateDateColumn()
  updatedAt!: Date;
}
]]></content>
  </change>
```

## server/src/routes/order.routes.ts

Relax Zod validation schema for creating orders. Allow shorter addresses, optional emails, and coerce numbers.

```typescript
<change>
    <file>server/src/routes/order.routes.ts</file>
    <description>Relax order validation schema (address min length, optional email, number coercion) to prevent validation errors on checkout.</description>
    <content><![CDATA[
import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { Order, OrderStatus } from '../entities/Order';
import { OrderItem } from '../entities/OrderItem';
import { validate } from '../middleware/validate';
import { authenticate, authorize } from '../middleware/auth';
import { z } from 'zod';
import { SaleService } from '../services/saleService';

const router = Router();
const orderRepo = AppDataSource.getRepository(Order);

// POST /api/orders
// Public endpoint for Website Checkout (Manual / Pay on Delivery)
const createOrderSchema = z.object({
    customerName: z.string().min(2),
    // Allow empty string or valid email, treat as optional
    customerEmail: z.union([z.string().email(), z.literal(''), z.string().length(0)]).optional(),
    customerPhone: z.string().min(9), // Relaxed from 10 to allow 9 digits (e.g. 722123456)
    shippingAddress: z.string().min(2), // Relaxed from 5 to 2 to allow short inputs like "CBD"
    items: z.array(z.object({
        productId: z.string(),
        quantity: z.coerce.number().min(1), // Coerce to handle string numbers
        price: z.coerce.number() // Coerce to handle string numbers
    })),
    paymentMethod: z.string().default('MANUAL')
});

router.post('/', validate(createOrderSchema), async (req, res) => {
    try {
        const { customerName, customerEmail, customerPhone, shippingAddress, items, paymentMethod } = req.body;

        const totalAmount = items.reduce((sum: number, item: any) => sum + (item.price * item.quantity), 0);

        const order = new Order();
        order.customerName = customerName;
        // Ensure email is saved as null if empty string
        order.customerEmail = customerEmail || undefined;
        order.customerPhone = customerPhone;
        order.shippingAddress = shippingAddress;
        order.totalAmount = totalAmount;
        order.status = OrderStatus.PENDING; // Manual orders are pending until verified

        order.items = items.map((i: any) => {
            const item = new OrderItem();
            item.product = { id: i.productId } as any;
            item.quantity = i.quantity;
            item.price = i.price;
            return item;
        });

        await orderRepo.save(order);

        // In a real app, trigger email notification here

        res.status(201).json({ 
            message: 'Order created successfully', 
            orderId: order.id,
            orderNumber: `ORD-${Date.now().toString().slice(-6)}` // Simple order ID generation
        });
    } catch (error) {
        console.error('Order Creation Error:', error);
        res.status(500).json({ error: 'Failed to create order' });
    }
});

// GET /api/orders
// Filterable list for Order Manager
router.get('/', authenticate, async (req, res) => {
    try {
        const status = req.query.status as string;
        const search = req.query.search as string;

        const query = orderRepo.createQueryBuilder('order')
            .leftJoinAndSelect('order.items', 'items')
            .leftJoinAndSelect('items.product', 'product')
            .orderBy('order.createdAt', 'DESC');

        if (status && status !== 'All Statuses' && status !== 'All') {
            query.andWhere('order.status = :status', { status });
        }

        if (search) {
            query.andWhere('(order.id LIKE :search OR order.customerName LIKE :search)', { search: `%${search}%` });
        }

        const orders = await query.take(50).getMany();

        // Transform for frontend dashboard with FULL DETAILS
        const formattedOrders = orders.map(o => ({
            id: o.id,
            orderNumber: o.id.substring(0, 8).toUpperCase(),
            customerName: o.customerName,
            customerEmail: o.customerEmail,
            customerPhone: o.customerPhone,
            shippingAddress: o.shippingAddress,
            date: new Date(o.createdAt).toLocaleDateString(),
            total: Number(o.totalAmount),
            status: o.status,
            paymentMethod: 'Manual',
            items: o.items.map(i => ({ 
                id: i.id,
                name: i.product?.name || 'Unknown Product', 
                sku: i.product?.sku || 'N/A',
                qty: i.quantity,
                price: Number(i.price),
                image: i.product?.imageUrl
            }))
        }));

        res.json(formattedOrders);
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: 'Failed to fetch orders' });
    }
});

// PATCH /api/orders/:id/status
// Update status (e.g. for Shipping Manager)
const updateStatusSchema = z.object({
    status: z.enum(['PENDING', 'PAID', 'SHIPPED', 'DELIVERED', 'FAILED']),
    trackingInfo: z.string().optional()
});

router.patch('/:id/status', authenticate, authorize(['ADMIN', 'MANAGER']), validate(updateStatusSchema), async (req, res) => {
    try {
        const { status } = req.body;

        // Load order with items and products to allow sale creation
        const order = await orderRepo.findOne({ 
            where: { id: req.params.id },
            relations: ['items', 'items.product'] 
        });

        if (!order) return res.status(404).json({ error: 'Order not found' });

        const previousStatus = order.status;
        order.status = status as OrderStatus;
        await orderRepo.save(order);

        // CRITICAL: If marking as PAID for the first time, convert to Sale
        // This updates dashboard stats and deducts inventory
        if (status === 'PAID' && previousStatus !== 'PAID') {
            try {
                await SaleService.createSaleFromOrder(order, req.user);
            } catch (saleError) {
                console.error("Failed to create sale record from order:", saleError);
                // Don't fail the request, but log it
            }
        }

        res.json(order);
    } catch (error) {
        res.status(500).json({ error: 'Failed to update order status' });
    }
});

// POST /api/orders/bulk
// For B2B CSV Uploads (Placeholder logic)
router.post('/bulk', authenticate, async (req, res) => {
    // Logic to parse CSV and create multiple orders would go here
    res.status(501).json({ message: 'Bulk upload not yet implemented' });
});

export default router;
]]></content>
  </change>

I am applying the fixes to the backend to resolve the "Validation Error" during Pay on Delivery. This involves relaxing the strict email and address requirements in the Order entity and the API route validation.

