  }
}

/* Keyframes */
@keyframes slideUp {
  0% { transform: translateY(20px); opacity: 0; }
  100% { transform: translateY(0); opacity: 1; }
}

@keyframes scaleUp {
  0% { transform: scale(0.95); opacity: 0; }
  100% { transform: scale(1); opacity: 1; }
}

@keyframes fadeIn {
  0% { opacity: 0; }
  100% { opacity: 1; }
}

@keyframes slideRight {
  0% { transform: translateX(100%); }
  100% { transform: translateX(0); }
}

@keyframes pulseOnce {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.2); }
}

/* --- ROBUST PRINT STYLES --- */
@media print {
  /* 1. Reset Body: Force white background and auto sizing */
  body {
    background: white !important;
    height: auto !important;
    width: 100% !important;
    overflow: visible !important;
    margin: 0 !important;
    padding: 0 !important;
  }

  /* 2. Hide Everything Else by default using visibility */
  /* We DO NOT use display: none on high-level elements because it kills child rendering inside modals */
  body * {
    visibility: hidden;
  }

  /* 3. Force The Print Container to Show */
  /* This targets the container wrapping InvoiceTemplate in modals */
  .print-force-container {
    visibility: visible !important;
