    display: block !important; /* Override tailwind .hidden */
    overflow: visible !important;
  }

  /* 4. Show Children of Print Container */
  .print-force-container * {
    visibility: visible !important;
  }

  /* 5. Specific Hiding - Only hide elements that definitely interfere and are NOT parents of the print container */
  nav, 
  header, 
  footer, 
  button, 
  input, 
  select,
