import BranchManager from './components/admin/BranchManager';
import CategoryManager from './components/admin/CategoryManager';
import FinanceManager from './components/admin/FinanceManager'; 
import NotFound from './components/NotFound';
import PartFinder from './components/PartFinder';
import AdminLogin from './components/AdminLogin';
import WarrantyPolicy from './components/WarrantyPolicy'; 
import { CartItem, Product, ViewState } from './types';
import { CheckCircle, MessageCircle, ArrowUp, Star, Quote, Package, Lock, Loader2, MapPin, Send, Shield, Settings, Globe, Users, PenTool, BarChart3, Target } from 'lucide-react';
import { apiClient } from './utils/apiClient';
import { CurrencyProvider } from './contexts/CurrencyContext';

function App() {
  const [currentView, setCurrentView] = useState<ViewState>('HOME');
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [isAiOpen, setIsAiOpen] = useState(false);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [toast, setToast] = useState<{message: string, type: ToastType} | null>(null);

  // Admin State
  const [adminModule, setAdminModule] = useState('dashboard');
  const [isAuthenticated, setIsAuthenticated] = useState(false);

  // Contact Form State
  const [contactForm, setContactForm] = useState({ name: '', email: '', subject: '', message: '' });
  const [contactSending, setContactSending] = useState(false);

  // Check for existing token on load
  useEffect(() => {
    const token = localStorage.getItem('masuma_auth_token');
    if (token) {
      setIsAuthenticated(true);
    }
  }, []);

  useEffect(() => {
    window.scrollTo(0, 0);
  }, [currentView]);

  useEffect(() => {
    const handleScroll = () => {
      setShowScrollTop(window.scrollY > 400);
    };
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollToTop = () => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  const showToast = (message: string, type: ToastType = 'success') => {
    setToast({ message, type });
  };

  const addToCart = (product: Product, quantity: number = 1) => {
    setCart(prev => {
      const existing = prev.find(item => item.id === product.id);
      if (existing) {
        return prev.map(item => 
          item.id === product.id ? { ...item, quantity: item.quantity + quantity } : item
        );
      }
      return [...prev, { ...product, quantity }];
    });

    const msg = quantity > 1 
      ? `Added ${quantity} x ${product.name} to cart`
      : `Added ${product.name} to cart`;

