                                <div className="text-[10px] text-gray-500">{item.sku}</div>
                            </div>
                            <div className="flex items-center gap-3 mx-2">
                                <button onClick={() => updateQty(item.id, -1)} className="p-1 bg-gray-100 hover:bg-gray-200 rounded"><Minus size={12} /></button>
                                <span className="text-sm font-bold w-4 text-center">{item.qty}</span>
                                <button onClick={() => updateQty(item.id, 1)} className="p-1 bg-gray-100 hover:bg-gray-200 rounded"><Plus size={12} /></button>
                            </div>
                            <div className="text-right">
                                <div className="text-sm font-bold text-masuma-dark">{(item.appliedPrice * item.qty).toLocaleString()}</div>
                                <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600 mt-1"><Trash2 size={12} /></button>
                            </div>
                        </div>
                    ))}
                </div>

                <div className="p-4 border-t border-gray-200 bg-white space-y-3">
                    <div className="grid grid-cols-3 gap-2">
                        {['CASH', 'MPESA', 'CHEQUE'].map(m => (
                            <button key={m} onClick={() => setPaymentMethod(m as PaymentMethod)} className={`p-2 text-[10px] font-bold uppercase border rounded flex flex-col items-center gap-1 ${paymentMethod === m ? 'bg-masuma-dark text-white border-masuma-dark' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}>
                                {m === 'CASH' && <Banknote size={16} />}
                                {m === 'MPESA' && <Smartphone size={16} />}
                                {m === 'CHEQUE' && <FileText size={16} />}
                                {m}
                            </button>
                        ))}
                    </div>
                    {(paymentMethod === 'MPESA' || paymentMethod === 'CHEQUE') && (
                        <div className="animate-fade-in">
                            <input type="text" value={paymentReference} onChange={e => setPaymentReference(e.target.value.toUpperCase())} placeholder={paymentMethod === 'MPESA' ? "Transaction Code" : "Cheque Number"} className="w-full p-2 border-2 border-masuma-orange rounded text-sm font-mono uppercase outline-none" />
                        </div>
                    )}
                    <div className="flex justify-between text-lg font-bold text-masuma-dark pt-2">
                        <span>Total</span>
                        <span>KES {total.toLocaleString()}</span>
                    </div>
                    <button onClick={handleCompleteSale} disabled={cart.length === 0 || isProcessing} className="w-full flex items-center justify-center gap-2 bg-masuma-orange text-white py-4 rounded font-bold hover:bg-orange-600 uppercase tracking-widest shadow-lg disabled:opacity-50">
                        {isProcessing ? 'Processing KRA...' : <><Printer size={20} /> Complete Sale</>}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default PosTerminal;
