import { Router } from 'express';
import { AppDataSource } from '../config/database';
import { MpesaTransaction } from '../entities/MpesaTransaction';
import { Order, OrderStatus } from '../entities/Order';
import { OrderItem } from '../entities/OrderItem';
import { authenticate, authorize } from '../middleware/auth';
import { MpesaService } from '../services/mpesaService';
import { Sale } from '../entities/Sale';
import { z } from 'zod';
import { validate } from '../middleware/validate';

const router = Router();
const mpesaRepo = AppDataSource.getRepository(MpesaTransaction);
const orderRepo = AppDataSource.getRepository(Order);

// GET /api/mpesa/logs
router.get('/logs', authenticate, authorize(['ADMIN', 'MANAGER']), async (req, res) => {
    try {
        const logs = await mpesaRepo.find({
            order: { createdAt: 'DESC' },
            take: 100,
            relations: ['order']
        });

        const formattedLogs = logs.map(log => ({
            id: log.id,
            checkoutRequestID: log.checkoutRequestID,
            phoneNumber: log.phoneNumber,
            amount: Number(log.amount),
            status: log.status,
            mpesaReceiptNumber: log.mpesaReceiptNumber,
            resultDesc: log.resultDesc,
            date: log.createdAt.toLocaleString()
        }));

        res.json(formattedLogs);
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: 'Failed to fetch M-Pesa logs' });
    }
});

// POST /api/mpesa/initiate-pos-payment
// Creates a PENDING order and triggers STK Push immediately
const posPaymentSchema = z.object({
    phoneNumber: z.string().min(9),
    items: z.array(z.object({
        productId: z.string(),
        quantity: z.number(),
        price: z.number()
    })),
    totalAmount: z.number(),
    customerName: z.string().optional(),
    customerId: z.string().optional()
});

router.post('/initiate-pos-payment', authenticate, validate(posPaymentSchema), async (req, res) => {
    try {
        const { phoneNumber, items, totalAmount, customerName, customerId } = req.body;

        // 1. Create PENDING Order first to track this transaction
        const order = new Order();
        order.orderNumber = `POS-${Date.now().toString().slice(-6)}`;
        order.customerName = customerName || 'Walk-in Customer';
        order.customerPhone = phoneNumber;
        order.totalAmount = totalAmount;
        order.status = OrderStatus.PENDING;
        order.paymentMethod = 'MPESA';

        order.items = items.map((i: any) => {
            const item = new OrderItem();
            item.product = { id: i.productId } as any;
            item.quantity = i.quantity;
            item.price = i.price;
            return item;
        });

        await orderRepo.save(order);

        // 2. Trigger STK Push
        const stkResponse = await MpesaService.initiateStkPush(order.id, phoneNumber, totalAmount);

        res.json({
            message: 'STK Push Initiated',
            checkoutRequestID: stkResponse.checkoutRequestID,
            orderId: order.id
        });

    } catch (error: any) {
        console.error("POS Payment Init Error:", error);
        res.status(500).json({ error: error.message || 'Failed to initiate M-Pesa payment' });
    }
});

// GET /api/mpesa/status/:checkoutRequestId
// Poll this endpoint to check if payment completed
router.get('/status/:checkoutRequestId', authenticate, async (req, res) => {
    try {
        const transaction = await mpesaRepo.findOne({
            where: { checkoutRequestID: req.params.checkoutRequestId },
            relations: ['order']
        });

        if (!transaction) {
            return res.status(404).json({ status: 'NOT_FOUND' });
        }

        if (transaction.status === 'COMPLETED') {
            // Fetch the Sale record created automatically by the callback
            const sale = await AppDataSource.getRepository(Sale).createQueryBuilder("sale")
                .where("JSON_EXTRACT(sale.paymentDetails, '$.orderReference') = :orderRef", { orderRef: transaction.order.orderNumber })
                .getOne();

            return res.json({ 
                status: 'COMPLETED', 
                sale: sale, // Return full sale object for receipt printing
                receiptNumber: transaction.mpesaReceiptNumber 
            });
        } else if (transaction.status === 'FAILED') {
             return res.json({ status: 'FAILED', reason: transaction.resultDesc });
        }

        res.json({ status: 'PENDING' });
    } catch (error) {
        res.status(500).json({ error: 'Check status failed' });
    }
});

export default router;
