            isWholesale: false,
            totalSpend: 0,
            lastVisit: new Date().toISOString()
        };
        selectCustomer(guestCustomer);
    };

    const total = cart.reduce((sum, item) => sum + (item.appliedPrice * item.qty), 0);

    const handleCompleteSale = async () => {
        if (paymentMethod === 'CHEQUE' && paymentReference.length < 3) {
            alert("Please enter the Cheque Number.");
            return;
        }

        // M-PESA WORKFLOW
        if (paymentMethod === 'MPESA') {
            if (paymentReference.length < 9) { // Expecting phone number
                alert("Please enter customer phone number for STK Push (e.g., 0722...)");
                return;
            }

            setIsProcessing(true);
            setMpesaStatus('pushing');

            try {
                // 1. Trigger STK Push via Backend
                const pushRes = await apiClient.post('/mpesa/initiate-pos-payment', {
                    phoneNumber: paymentReference,
                    items: cart.map(i => ({ productId: i.id, quantity: i.qty, price: i.appliedPrice })),
                    totalAmount: total,
                    customerName: customer?.name,
                    customerId: customer?.id === 'GUEST' ? undefined : customer?.id
                });

                const checkoutId = pushRes.data.checkoutRequestID;
                setMpesaStatus('waiting');

                // 2. Poll for Status
                const pollInterval = setInterval(async () => {
                    try {
                        const statusRes = await apiClient.get(`/mpesa/status/${checkoutId}`);
                        const status = statusRes.data.status;

                        if (status === 'COMPLETED') {
                            clearInterval(pollInterval);
                            setMpesaStatus('success');
                            setLastSale(statusRes.data.sale); // Backend returns the created sale
                            setCart([]);
                            setCustomer(null);
                            setPaymentMethod('CASH');
                            setPaymentReference('');
                            setIsProcessing(false);
                        } else if (status === 'FAILED') {
                            clearInterval(pollInterval);
                            setMpesaStatus('failed');
                            setMpesaStatusMsg(statusRes.data.reason || 'Transaction Failed/Cancelled');
                            setIsProcessing(false);
                        }
                    } catch (e) {
                        console.error("Polling error", e);
                    }
                }, 3000);

                // Timeout after 60s
                setTimeout(() => {
                    clearInterval(pollInterval);
                    if (mpesaStatus !== 'success') {
                        setMpesaStatus('failed');
                        setMpesaStatusMsg('Timeout: Payment verification took too long.');
                        setIsProcessing(false);
                    }
                }, 60000);

            } catch (error: any) {
                setMpesaStatus('failed');
                setMpesaStatusMsg(error.response?.data?.error || 'Failed to initiate STK Push');
                setIsProcessing(false);
            }
            return;
        }

        // STANDARD CASH/CHEQUE WORKFLOW
        setIsProcessing(true);
        try {
            const payload = {
                items: cart.map(i => ({ 
                    productId: i.id, 
                    name: i.name, 
                    quantity: i.qty, 
                    price: i.appliedPrice,
                    sku: i.sku,
                    oem: (i.oemNumbers && i.oemNumbers.length > 0) ? i.oemNumbers[0] : ''
                })),
                totalAmount: total,
                paymentMethod,
                paymentDetails: { reference: paymentReference },
                customerId: customer?.id === 'GUEST' ? undefined : customer?.id,
                customerName: customer?.name
            };

            const response = await apiClient.post('/sales', payload);
            setLastSale(response.data);
            setCart([]);
            setCustomer(null);
            setPaymentMethod('CASH');
            setPaymentReference('');
        } catch (error: any) {
            alert('Sale Failed: ' + (error.response?.data?.error || 'Network Error'));
        } finally {
            setIsProcessing(false);
        }
    };

    const handlePrintReceipt = () => {
        setTimeout(() => {
            window.print();
        }, 500);
    };

    if (lastSale) {
        return (
            <div className="flex items-center justify-center h-[calc(100vh-100px)] animate-scale-up">
                {/* Hidden Print Container - Forces 80mm Receipt layout */}
                <div className="hidden print-force-container">
                    <InvoiceTemplate data={lastSale} type="RECEIPT" ref={printRef} />
                </div>

                <div className="bg-white p-8 rounded shadow-lg border border-gray-200 w-96 text-center">
                    <div className="w-16 h-16 bg-green-100 text-green-600 rounded-full flex items-center justify-center mx-auto mb-4">
                        <CheckCircle size={32} />
                    </div>
                    <h2 className="text-xl font-bold text-masuma-dark mb-1">Sale Completed</h2>
                    <p className="text-gray-500 text-sm mb-6">Receipt #{lastSale.receiptNumber}</p>

                    <div className="bg-gray-50 p-4 border border-gray-200 rounded mb-6 text-left">
                        <div className="flex justify-between items-center mb-2">
                            <span className="text-[10px] font-bold text-gray-500 uppercase">KRA Control Code</span>
                            <span className="text-xs font-mono font-bold">{lastSale.kraControlCode || 'PENDING'}</span>
                        </div>
                        <div className="flex justify-center py-2">
                             <QrCode size={64} className="text-masuma-dark" />
                        </div>
                    </div>

                    <div className="flex gap-3">
                        <button onClick={handlePrintReceipt} className="flex-1 bg-gray-800 text-white py-2 rounded font-bold text-sm uppercase flex items-center justify-center gap-2 hover:bg-gray-700">
                            <Printer size={16} /> Print Receipt
                        </button>
                        <button onClick={() => setLastSale(null)} className="flex-1 bg-masuma-orange text-white py-2 rounded font-bold text-sm uppercase hover:bg-orange-600">
                            New Sale
                        </button>
                    </div>
                </div>
            </div>
        );
    }

    return (
        <div className="flex h-[calc(100vh-100px)] gap-6 font-sans">
            {/* Left: Product Selection */}
            <div className="flex-1 flex flex-col bg-white rounded shadow-sm border border-gray-200 overflow-hidden">
                {/* ... Search and List (Unchanged) ... */}
                <div className="p-4 border-b border-gray-200 flex gap-4">
                    <div className="relative flex-1">
                        <input 
                            ref={searchInputRef}
                            type="text" 
                            className="w-full pl-10 pr-4 py-3 bg-gray-100 border border-transparent focus:bg-white focus:border-masuma-orange outline-none rounded"
                            placeholder="Scan barcode or search SKU / Name..."
                            value={searchTerm}
                            onChange={(e) => handleProductSearch(e.target.value)}
                            autoFocus
                        />
                        <Search className="absolute left-3 top-3.5 text-gray-400" size={18} />
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto p-4">
                    {isSearching ? (
                         <div className="flex justify-center pt-10"><Loader2 className="animate-spin text-masuma-orange"/></div>
                    ) : searchTerm ? (
                        <div className="grid grid-cols-2 lg:grid-cols-3 gap-4">
                            {searchResults.map(p => {
                                const isOutOfStock = (p.quantity || 0) <= 0;
                                return (
                                    <div 
                                        key={p.id} 
                                        onClick={() => !isOutOfStock && addToCart(p)}
                                        className={`p-3 border rounded transition group relative ${
                                            isOutOfStock 
                                                ? 'border-red-100 bg-red-50 cursor-not-allowed opacity-80' 
                                                : 'border-gray-200 hover:border-masuma-orange cursor-pointer bg-gray-50 hover:bg-white'
                                        }`}
                                    >
                                        <div className="flex justify-between items-start mb-1">
                                            <div className="text-xs font-bold text-gray-500">{p.sku}</div>
                                            {isOutOfStock && (
                                                <span className="bg-red-600 text-white text-[9px] font-bold px-1.5 rounded uppercase flex items-center gap-1">
                                                    <AlertTriangle size={8} /> Sold Out
                                                </span>
                                            )}
                                        </div>
                                        <div className="font-bold text-sm text-masuma-dark line-clamp-2 h-10 leading-tight">{p.name}</div>
                                        <div className="mt-2 flex justify-between items-end">
                                            <div className="text-masuma-orange font-bold">KES {p.price.toLocaleString()}</div>
                                            <div className="text-[10px] text-gray-400 font-bold">{p.quantity} left</div>
                                        </div>
                                    </div>
                                );
                            })}
                            {searchResults.length === 0 && <div className="col-span-3 text-center text-gray-400">No products found</div>}
                        </div>
                    ) : (
                         <div className="flex flex-col items-center justify-center h-full text-gray-400">
                            <Search size={48} className="mb-4 opacity-20" />
                            <p>Start typing to search inventory</p>
                        </div>
                    )}
                </div>
            </div>

            {/* Right: Cart & Checkout */}
            <div className="w-96 flex flex-col bg-white rounded shadow-sm border border-gray-200 overflow-hidden relative">
                <div className="p-4 bg-masuma-dark text-white border-b border-gray-800 flex justify-between items-center">
                    <h3 className="font-bold uppercase tracking-wider">Current Sale</h3>
                    <span className="bg-masuma-orange px-2 py-1 text-xs rounded font-bold">{cart.length} Items</span>
                </div>

                {/* Customer Selector (Unchanged) */}
                <div className="p-3 border-b border-gray-200 bg-gray-50">
                    {!customer ? (
                        <button 
                            onClick={() => setIsCustomerSearchOpen(true)}
                            className="w-full py-2 border-2 border-dashed border-gray-300 rounded text-gray-500 text-xs font-bold uppercase hover:border-masuma-orange hover:text-masuma-orange transition flex items-center justify-center gap-2"
                        >
                            <User size={16} /> Select Customer
                        </button>
                    ) : (
                        <div className="flex justify-between items-center bg-white border border-gray-200 p-2 rounded">
                             <div className="flex flex-col">
                                 <span className="text-xs font-bold text-masuma-dark">{customer.name}</span>
                                 <span className="text-[9px] text-gray-400 uppercase">Customer</span>
                             </div>
                             <button onClick={() => { setCustomer(null); setIsCustomerSearchOpen(false); }} className="text-gray-400 hover:text-red-500"><X size={16} /></button>
                        </div>
                    )}
                </div>

                {isCustomerSearchOpen && !customer && (
                    <div className="absolute top-[116px] left-0 w-full bg-white shadow-xl border-b border-gray-200 z-10 p-2 animate-slide-up">
                        <input 
                            type="text" 
                            autoFocus
                            placeholder="Search Customer..."
                            className="w-full p-2 border border-gray-300 rounded text-sm mb-2"
                            value={customerSearchTerm}
                            onChange={(e) => handleSearchCustomer(e.target.value)}
                        />
                        <div className="max-h-40 overflow-y-auto space-y-1">
                            {foundCustomers.map(c => (
                                <div key={c.id} onClick={() => selectCustomer(c)} className="p-2 hover:bg-gray-100 cursor-pointer rounded text-sm">{c.name}</div>
                            ))}
                             {customerSearchTerm && (
                                <div onClick={handleUseCustomCustomer} className="p-2 hover:bg-orange-50 cursor-pointer rounded text-sm flex items-center gap-2 text-masuma-orange border-t border-gray-100 mt-1">
                                    <Plus size={14} /> <span className="font-bold">Use "{customerSearchTerm}"</span>
                                </div>
                            )}
                        </div>
                        <button onClick={() => setIsCustomerSearchOpen(false)} className="w-full text-center text-xs text-red-500 mt-2 py-1">Cancel</button>
                    </div>
                )}

                {/* Cart Items (Unchanged) */}
                <div className="flex-1 overflow-y-auto p-2 space-y-2 bg-gray-50">
                    {cart.map((item, idx) => (
                        <div key={idx} className="bg-white p-3 rounded shadow-sm border border-gray-100 flex justify-between items-center">
                            <div className="flex-1">
                                <div className="text-xs font-bold text-gray-800">{item.name}</div>
                                <div className="text-[10px] text-gray-500">{item.sku}</div>
                            </div>
                            <div className="flex items-center gap-3 mx-2">
                                <button onClick={() => updateQty(item.id, -1)} className="p-1 bg-gray-100 hover:bg-gray-200 rounded"><Minus size={12} /></button>
                                <span className="text-sm font-bold w-4 text-center">{item.qty}</span>
                                <button onClick={() => updateQty(item.id, 1)} className="p-1 bg-gray-100 hover:bg-gray-200 rounded"><Plus size={12} /></button>
                            </div>
                            <div className="text-right">
                                <div className="text-sm font-bold text-masuma-dark">{(item.appliedPrice * item.qty).toLocaleString()}</div>
                                <button onClick={() => removeFromCart(item.id)} className="text-red-400 hover:text-red-600 mt-1"><Trash2 size={12} /></button>
                            </div>
                        </div>
                    ))}
                </div>

                {/* Checkout & Payment Area */}
                <div className="p-4 border-t border-gray-200 bg-white space-y-3">

                    {/* M-PESA Overlay */}
                    {isProcessing && paymentMethod === 'MPESA' && (
                        <div className="absolute inset-0 bg-white z-20 flex flex-col items-center justify-center text-center p-4 animate-fade-in">
                             {mpesaStatus === 'waiting' || mpesaStatus === 'pushing' ? (
                                 <>
                                     <Loader2 size={48} className="animate-spin text-green-600 mb-4" />
                                     <h4 className="text-lg font-bold text-masuma-dark uppercase">Confirming Payment</h4>
                                     <p className="text-sm text-gray-500 mt-2">Prompt sent to {paymentReference}</p>
                                     <p className="text-xs text-gray-400 mt-1">Waiting for PIN...</p>
                                 </>
                             ) : mpesaStatus === 'failed' ? (
                                 <>
                                    <AlertTriangle size={48} className="text-red-600 mb-4" />
                                    <h4 className="text-lg font-bold text-red-600 uppercase">Transaction Failed</h4>
                                    <p className="text-sm text-gray-500 mt-2">{mpesaStatusMsg}</p>
                                    <button onClick={() => setIsProcessing(false)} className="mt-4 px-6 py-2 bg-gray-200 rounded font-bold uppercase text-xs">Back</button>
                                 </>
                             ) : null}
                        </div>
                    )}

                    {/* Payment Selector */}
                    <div className="grid grid-cols-3 gap-2">
                        <button onClick={() => setPaymentMethod('CASH')} className={`p-2 text-[10px] font-bold uppercase border rounded flex flex-col items-center gap-1 ${paymentMethod === 'CASH' ? 'bg-masuma-dark text-white border-masuma-dark' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}>
                            <Banknote size={16} /> Cash
                        </button>
                        <button onClick={() => setPaymentMethod('MPESA')} className={`p-2 text-[10px] font-bold uppercase border rounded flex flex-col items-center gap-1 ${paymentMethod === 'MPESA' ? 'bg-green-600 text-white border-green-600' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}>
                            <Smartphone size={16} /> M-Pesa
                        </button>
                        <button onClick={() => setPaymentMethod('CHEQUE')} className={`p-2 text-[10px] font-bold uppercase border rounded flex flex-col items-center gap-1 ${paymentMethod === 'CHEQUE' ? 'bg-blue-600 text-white border-blue-600' : 'bg-white text-gray-500 border-gray-200 hover:bg-gray-50'}`}>
                            <FileText size={16} /> Cheque
                        </button>
                    </div>

                    {/* Reference Input */}
                    <div className="animate-fade-in">
                        <input 
                            type="text" 
                            value={paymentReference}
                            onChange={e => setPaymentReference(e.target.value.toUpperCase())}
                            placeholder={paymentMethod === 'MPESA' ? "Enter Customer Phone (e.g. 0722...)" : paymentMethod === 'CHEQUE' ? "Cheque Number" : "Optional Notes"}
                            className="w-full p-2 border-2 border-masuma-orange rounded text-sm font-mono uppercase outline-none"
                        />
                    </div>

                    <div className="flex justify-between text-lg font-bold text-masuma-dark pt-2">
                        <span>Total</span>
                        <span>KES {total.toLocaleString()}</span>
                    </div>
                    <button 
                        onClick={handleCompleteSale}
                        disabled={cart.length === 0 || isProcessing}
                        className="w-full flex items-center justify-center gap-2 bg-masuma-orange text-white py-4 rounded font-bold hover:bg-orange-600 uppercase tracking-widest shadow-lg disabled:opacity-50"
                    >
                        {isProcessing && paymentMethod !== 'MPESA' ? 'Processing...' : <><Printer size={20} /> {paymentMethod === 'MPESA' ? 'Push & Verify' : 'Complete Sale'}</>}
                    </button>
                </div>
            </div>
        </div>
    );
};

export default PosTerminal;
]]></content>
  </change>
